class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedPaths = ["/promo"]
    private let maxDiscountPercentage = 100
    private let maxPromoCodeLength = 50
    
    private init() {}
    
    @discardableResult
    func handleUniversalLink(_ url: URL) -> Bool {
        guard validateURL(url) else {
            print("Invalid URL: \(url)")
            return false
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("Failed to parse URL components")
            return false
        }
        
        guard let host = components.host?.lowercased(),
              allowedHosts.contains(host) else {
            print("Host not allowed: \(components.host ?? "nil")")
            return false
        }
        
        let path = components.path.lowercased()
        guard allowedPaths.contains(path) else {
            print("Path not allowed: \(path)")
            return false
        }
        
        if path == "/promo" {
            return handlePromoLink(components: components)
        }
        
        return false
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard url.scheme == "https" else {
            print("Only HTTPS scheme allowed")
            return false
        }
        
        return true
    }
    
    private func handlePromoLink(components: URLComponents) -> Bool {
        guard let queryItems = components.queryItems else {
            print("No query parameters found")
            return false
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name.lowercased() {
            case "code":
                if let value = item.value {
                    promoCode = sanitizePromoCode(value)
                }
            case "discount":
                if let value = item.value {
                    discount = sanitizeDiscount(value)
                }
            default:
                break
            }
        }
        
        guard let validPromoCode = promoCode,
              let validDiscount = discount else {
            print("Missing or invalid required parameters")
            return false
        }
        
        guard validatePromoCode(validPromoCode) else {
            print("Promo code validation failed")
            return false
        }
        
        guard validateDiscount(validDiscount) else {
            print("Discount validation failed")
            return false
        }
        
        guard AuthorizationManager.shared.isUserAuthenticated() else {
            print("User must be authenticated to apply promo code")
            PendingPromoManager.shared.storePendingPromo(code: validPromoCode, discount: validDiscount)
            NotificationCenter.default.post(name: .authenticationRequired, object: nil)
            return false
        }
        
        guard AuthorizationManager.shared.canApplyPromoCode() else {
            print("User not authorized to apply promo codes")
            return false
        }
        
        applyPromoCode(code: validPromoCode, discount: validDiscount)
        return true
    }
    
    private func sanitizePromoCode(_ code: String) -> String? {
        let trimmed = code.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard trimmed.count > 0 && trimmed.count <= maxPromoCodeLength else {
            return nil
        }
        
        let allowedCharacters = CharacterSet.alphanumerics
        guard trimmed.unicodeScalars.allSatisfy({ allowedCharacters.contains($0) }) else {
            return nil
        }
        
        return trimmed.uppercased()
    }
    
    private func sanitizeDiscount(_ discountString: String) -> Int? {
        guard let discount = Int(discountString) else {
            return nil
        }
        
        return discount
    }
    
    private func validatePromoCode(_ code: String) -> Bool {
        guard code.count >= 3 && code.count <= maxPromoCodeLength else {
            return false
        }
        
        let pattern = "^[A-Z0-9]+$"
        guard let regex = try? NSRegularExpression(pattern: pattern),
              regex.firstMatch(in: code, range: NSRange(code.startIndex..., in: code)) != nil else {
            return false
        }
        
        return true
    }
    
    private func validateDiscount(_ discount: Int) -> Bool {
        return discount > 0 && discount <= maxDiscountPercentage
    }
    
    private func applyPromoCode(code: String, discount: Int) {
        Task {
            do {
                try await PromoCodeManager.shared.applyPromoCode(code: code, discount: discount)
                
                await MainActor.run {
                    NotificationCenter.default.post(
                        name: .promoCodeApplied,
                        object: nil,
                        userInfo: ["code": code, "discount": discount]
                    )
                }
            } catch {
                print("Failed to apply promo code: \(error)")
                await MainActor.run {
                    NotificationCenter.default.post(
                        name: .promoCodeFailed,
                        object: nil,
                        userInfo: ["error": error.localizedDescription]
                    )
                }
            }
        }
    }
}

class AuthorizationManager {
    static let shared = AuthorizationManager()
    
    private var currentUser: User?
    
    private init() {}
    
    func isUserAuthenticated() -> Bool {
        return currentUser != nil
    }
    
    func canApplyPromoCode() -> Bool {
        guard let user = currentUser else {
            return false
        }
        
        return user.isActive && !user.isBanned
    }
    
    func setCurrentUser(_ user: User?) {
        currentUser = user
    }
    
    func getCurrentUser() -> User? {
        return currentUser
    }
}

