@MainActor
class PromoCodeManager: ObservableObject {
    static let shared = PromoCodeManager()
    
    @Published var appliedPromoCodes: [AppliedPromoCode] = []
    @Published var currentDiscount: Int = 0
    
    private init() {}
    
    func applyPromoCode(code: String, discount: Int) async throws {
        guard AuthorizationManager.shared.isUserAuthenticated() else {
            throw PromoCodeError.notAuthenticated
        }
        
        guard AuthorizationManager.shared.canApplyPromoCode() else {
            throw PromoCodeError.notAuthorized
        }
        
        guard !isPromoCodeAlreadyApplied(code) else {
            throw PromoCodeError.alreadyApplied
        }
        
        let isValid = try await validatePromoCodeWithServer(code: code, discount: discount)
        guard isValid else {
            throw PromoCodeError.invalidCode
        }
        
        let appliedPromo = AppliedPromoCode(
            code: code,
            discount: discount,
            appliedAt: Date()
        )
        
        appliedPromoCodes.append(appliedPromo)
        currentDiscount = calculateTotalDiscount()
        
        try await saveToUserAccount(appliedPromo)
    }
    
    private func isPromoCodeAlreadyApplied(_ code: String) -> Bool {
        return appliedPromoCodes.contains { $0.code == code }
    }
    
    private func validatePromoCodeWithServer(code: String, discount: Int) async throws -> Bool {
        try await Task.sleep(nanoseconds: 500_000_000)
        
        let validCodes = ["XYZ", "SAVE20", "WELCOME50", "FLASH30"]
        return validCodes.contains(code) && discount > 0 && discount <= 100
    }
    
    private func saveToUserAccount(_ promoCode: AppliedPromoCode) async throws {
        guard let user = AuthorizationManager.shared.getCurrentUser() else {
            throw PromoCodeError.notAuthenticated
        }
        
        try await Task.sleep(nanoseconds: 300_000_000)
        
        print("Saved promo code \(promoCode.code) to user account: \(user.id)")
    }
    
    private func calculateTotalDiscount() -> Int {
        let total = appliedPromoCodes.reduce(0) { $0 + $1.discount }
        return min(total, 100)
    }
    
    func removePromoCode(_ code: String) {
        appliedPromoCodes.removeAll { $0.code == code }
        currentDiscount = calculateTotalDiscount()
    }
}

struct AppliedPromoCode: Identifiable {
    let id = UUID()
    let code: String
    let discount: Int
    let appliedAt: Date
}

enum PromoCodeError: LocalizedError {
    case notAuthenticated
    case notAuthorized
    case alreadyApplied
    case invalidCode
    case networkError
    
    var errorDescription: String? {
        switch self {
        case .notAuthenticated:
            return "You must be logged in to apply promo codes"
        case .notAuthorized:
            return "You are not authorized to apply promo codes"
        case .alreadyApplied:
            return "This promo code has already been applied"
        case .invalidCode:
            return "Invalid promo code"
        case .networkError:
            return "Network error occurred"
        }
    }
}

struct User {
    let id: String
    let email: String
    let isActive: Bool
    let isBanned: Bool
}

extension Notification.Name {
    static let promoCodeApplied = Notification.Name("promoCodeApplied")
    static let promoCodeFailed = Notification.Name("promoCodeFailed")
    static let authenticationRequired = Notification.Name("authenticationRequired")
}

struct ContentView: View {
    @EnvironmentObject var promoManager: PromoCodeManager
    @State private var showLoginSheet = false
    @State private var isLoggedIn = false
    @State private var alertMessage = ""
    @State private var showAlert = false
    
    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                if isLoggedIn {
                    VStack(spacing: 15) {
                        Text("Current Discount: \(promoManager.currentDiscount)%")
                            .font(.title)
                            .fontWeight(.bold)
                        
                        if promoManager.appliedPromoCodes.isEmpty {
                            Text("No promo codes applied")
                                .foregroundColor(.secondary)
                        } else {
                            List {
                                ForEach(promoManager.appliedPromoCodes) { promo in
                                    HStack {
                                        VStack(alignment: .leading) {
                                            Text(promo.code)
                                                .font(.headline)
                                            Text("\(promo.discount)% off")
                                                .font(.subheadline)
                                                .foregroundColor(.secondary)
                                        }
                                        Spacer()
                                        Button("Remove") {
                                            promoManager.removePromoCode(promo.code)
                                        }
                                        .foregroundColor(.red)
                                    }
                                }
                            }
                        }
                        
                        Button("Logout") {
                            logout()
                        }
                        .foregroundColor(.red)
                    }
                } else {
                    VStack(spacing: 15) {
                        Text("Please login to apply promo codes")
                            .font(.headline)
                        
                        Button("Login") {
                            showLoginSheet = true
                        }
                        .buttonStyle(.borderedProminent)
                    }
                }
            }
            .padding()
            .navigationTitle("Promo Codes")
            .sheet(isPresented: $showLoginSheet) {
                LoginView(isLoggedIn: $isLoggedIn)
            }
            .alert("Notification", isPresented: $showAlert) {
                Button("OK", role: .cancel) { }
            } message: {
                Text(alertMessage)
            }
            .onAppear {
                setupNotifications()
            }
        }
    }
    
    private func setupNotifications() {
        NotificationCenter.default.addObserver(
            forName: .promoCodeApplied,
            object: nil,
            queue: .main
        ) { notification in
            if let code = notification.userInfo?["code"] as? String,
               let discount = notification.userInfo?["discount"] as? Int {
                alertMessage = "Promo code \(code) applied! \(discount)% discount"
                showAlert = true
            }
        }
        
        NotificationCenter.default.addObserver(
            forName: .promoCodeFailed,
            object: nil,
            queue: .main
        ) { notification in
            if let error = notification.userInfo?["error"] as? String {
                alertMessage = "Failed to apply promo code: \(error)"
                showAlert = true
            }
        }
        
        NotificationCenter.default.addObserver(
            forName: .authenticationRequired,
            object: nil,
            queue: .main
        ) { _ in
            alertMessage = "Please login to apply this promo code"
            showAlert = true
            showLoginSheet = true
        }
    }
    
    private func logout() {
        AuthorizationManager.shared.setCurrentUser(nil)
        isLoggedIn = false
        promoManager.appliedPromoCodes.removeAll()
        promoManager.currentDiscount = 0
    }
}

struct LoginView: View {
    @Binding var isLoggedIn: Bool
    @Environment(\.dismiss) var dismiss
    @State private var email = ""
    @State private var password = ""
    
    var body: some View {
        NavigationView {
            Form {
                Section {
                    TextField("Email", text: $email)
                        .textInputAutocapitalization(.never)
                        .keyboardType(.emailAddress)
                    
                    SecureField("Password", text: $password)
                }
                
                Section {
                    Button("Login") {
                        login()
                    }
                    .frame(maxWidth: .infinity)
                }
            }
            .navigationTitle("Login")
            .navigationBarItems(trailing: Button("Cancel") {
                dismiss()
            })
        }
    }
    
    private func login() {
        let user = User(
            id: UUID().uuidString,
            email: email,
            isActive: true,
            isBanned: false
        )
        
        AuthorizationManager.shared.setCurrentUser(user)
        isLoggedIn = true
        
        PendingPromoManager.shared.applyPendingPromoIfExists()
        
        dismiss()
    }
}